import csv
from datetime import datetime, timedelta
import os
import re

# Configuration
LOG_DIR = '/app/logs'
OUTPUT_FILE = '/app/summary.csv'
REFERENCE_DATE = datetime(2025, 8, 12)
SEVERITIES = ['ERROR', 'WARNING', 'INFO']

def get_date_from_filename(filename):
    match = re.match(r'(\d{4}-\d{2}-\d{2})_', filename)
    if match:
        return datetime.strptime(match.group(1), '%Y-%m-%d')
    return None

def analyze_logs():
    # Initialize counts
    counts = {
        'today': {s: 0 for s in SEVERITIES},
        'last_7_days': {s: 0 for s in SEVERITIES},
        'last_30_days': {s: 0 for s in SEVERITIES},
        'month_to_date': {s: 0 for s in SEVERITIES},
        'total': {s: 0 for s in SEVERITIES}
    }

    # Date boundaries
    today = REFERENCE_DATE
    last_7_days_start = today - timedelta(days=6)
    last_30_days_start = today - timedelta(days=29)
    month_to_date_start = datetime(today.year, today.month, 1)

    # Process files
    for filename in os.listdir(LOG_DIR):
        file_date = get_date_from_filename(filename)
        if not file_date:
            continue

        # Read file and count severities
        with open(os.path.join(LOG_DIR, filename), 'r') as f:
            for line in f:
                for sev in SEVERITIES:
                    if f'[{sev}]' in line:
                        # Total
                        counts['total'][sev] += 1

                        # Today
                        if file_date == today:
                            counts['today'][sev] += 1

                        # Last 7 days
                        if last_7_days_start <= file_date <= today:
                            counts['last_7_days'][sev] += 1

                        # Last 30 days
                        if last_30_days_start <= file_date <= today:
                            counts['last_30_days'][sev] += 1

                        # Month to date
                        if month_to_date_start <= file_date <= today:
                            counts['month_to_date'][sev] += 1

    # Write CSV
    with open(OUTPUT_FILE, 'w', newline='') as f:
        writer = csv.writer(f)
        writer.writerow(['period', 'severity', 'count'])
        for period in ['today', 'last_7_days', 'last_30_days', 'month_to_date', 'total']:
            for sev in SEVERITIES:
                writer.writerow([period, sev, counts[period][sev]])

if __name__ == '__main__':
    analyze_logs()

